/**
 * Secure dynamic SQL query builder using Slick's parameterized sql interpolator.
 * 
 * IMPORTANT: We never splice user input directly into SQL strings.
 * All user values are passed as bound parameters using Slick's sql"...$param" syntax,
 * which uses PreparedStatement parameter binding under the hood.
 */
object SecureSqlBuilder {

  /**
   * Concatenates SQLActionBuilder fragments safely.
   */
  def concat(builders: SQLActionBuilder*): SQLActionBuilder = {
    builders.reduceLeft { (a, b) =>
      SQLActionBuilder(a.queryParts ++ b.queryParts, (p: Unit, pp: SetParameter[Unit]) => {
        a.unitPConv.apply(p, pp)
        b.unitPConv.apply(p, pp)
      })
    }
  }

  def buildProductSearchQuery(filters: SearchFilters): SQLActionBuilder = {
    val baseQuery = sql"SELECT id, name, description, category, price, brand, in_stock FROM products WHERE 1=1"

    val conditions = Seq.newBuilder[SQLActionBuilder]

    filters.name.foreach { name =>
      val pattern = s"%${name.toLowerCase}%"
      conditions += sql" AND LOWER(name) LIKE $pattern"
    }

    filters.category.foreach { category =>
      conditions += sql" AND category = $category"
    }

    filters.brand.foreach { brand =>
      conditions += sql" AND brand = $brand"
    }

    filters.minPrice.foreach { minPrice =>
      conditions += sql" AND price >= $minPrice"
    }

    filters.maxPrice.foreach { maxPrice =>
      conditions += sql" AND price <= $maxPrice"
    }

    filters.inStock.foreach { inStock =>
      conditions += sql" AND in_stock = $inStock"
    }

    // Sort column is whitelisted - never interpolated from user input directly
    val sortClause: SQLActionBuilder = filters.sortBy match {
      case Some("name")  => sql" ORDER BY name"
      case Some("price") => sql" ORDER BY price"
      case Some("brand") => sql" ORDER BY brand"
      case Some("category") => sql" ORDER BY category"
      case _             => sql" ORDER BY id"
    }

    val orderClause: SQLActionBuilder = filters.sortOrder match {
      case Some(o) if o.equalsIgnoreCase("DESC") => sql" DESC"
      case _ => sql" ASC"
    }

    val limit = filters.limit.getOrElse(50).min(100).max(1)
    val offset = filters.offset.getOrElse(0).max(0)
    val paginationClause = sql" LIMIT $limit OFFSET $offset"

    val allParts = Seq(baseQuery) ++ conditions.result() ++ Seq(sortClause, orderClause, paginationClause)
    concat(allParts: _*)
  }
}

